external_knowledge:
- "Shining stars" refers to players who have achieved the highest game scores in their sessions;
- "Gaming journey" metaphorically describes the progression and outcomes of game sessions;
- "Voyages across various platforms" refers to the different platforms on which the sessions took place (PC, mobile, etc.);
- "Reaching the peak" means achieving the highest score in a game session.

sql:
SELECT players.player_name, players.country
FROM players
JOIN game_sessions ON players.player_id = game_sessions.player_id;

SELECT AVG(duration) AS average_duration
FROM game_sessions
WHERE game_id = 1;

SELECT AVG(p.age) AS average_age
FROM players p
JOIN player_achievements pa ON p.player_id = pa.player_id;
